previewCss:
.darma-loader-darma-custom-294 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #0891b2);
  --l:#0000 45%,var(--loader-color, #0891b2) 0 55%,#0000 0;
  --g:0/300% 100% no-repeat text;
  background: 
    linear-gradient(-60deg,var(--l)) var(--g),
    linear-gradient( 60deg,var(--l)) var(--g);
  animation: darma-loader-darma-custom-294-l7 4s linear infinite;
}
.darma-loader-darma-custom-294:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-294-l7 {
  0%  {background-position: 100%,0   }
  50% {background-position: 0   ,0   }
  to  {background-position: 0   ,100%}
}

